// ============================================================================
//  App.jsx  —  esmo MOBA 3D 整合版（明亮 / 真實地圖細節 / 串接邏輯大腦）
// ----------------------------------------------------------------------------
//  架構（Local Server Pattern，全部內聯以便 artifact 沙盒執行）：
//    LogicEngine     ── 對戰大腦：每 tick 推進真實模擬，產生可序列化 snapshot
//    useGameStore    ── 渲染狀態橋：持有 prev / snapshot / subTRef
//    useLocalServer  ── 驅動水管：按下 Start → 定時 tick 大腦 → 推快照進 store
//    GameView(App)   ── 3D 渲染殼：只讀 store，useFrame 等價迴圈做平滑內插
//
//  ⚠ 沙盒只支援 three r128，沒有 @react-three/fiber/drei/postprocessing/zustand，
//    故此預覽用原生 three r128（視覺等同 R3F 版，依先前要求暫不掛 Bloom/SSAO）。
//  ⚠ 回到你的 Vite 專案時：把內聯 LogicEngine 換成 import './LogicEngine'、
//    把渲染換成上一份 MobaView3D.jsx（R3F + EffectComposer），合約完全相同。
//
//  🖼 你的彩色底圖沒上傳成功 → 先用程序化 Rift 底圖。把下面 MOBA_MAP_DATAURI
//    設成你圖檔的 "data:image/png;base64,...." 即會自動改用你的真實底圖。
// ============================================================================

import React, { useRef, useEffect, useState, useCallback } from "react";
import * as THREE from "three";
// Phase 9：平台資料流入口（正式 roster 注入介面；目前 no-op，不改戰鬥邏輯）
import { buildEngineSlots, applyRosterToEngine } from "./battle/moba/mobaRosterAdapter.js";

const MOBA_MAP_DATAURI = 'data:image/jpeg;base64,';  // 你上傳的 LOL 地圖（1024 JPEG） // ← 貼上你地圖的 base64 data URI 即可替換底圖

// ── 工具 ────────────────────────────────────────────────────────────────────
const lerp = (a, b, t) => a + (b - a) * t;
const clamp = (v, a, b) => Math.max(a, Math.min(b, v));
const ease = (t) => (t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2);
const dist = (a, b) => Math.hypot(a.x - b.x, a.y - b.y);
const fmtT = (s) => `${Math.floor(s / 60)}:${(Math.floor(s) % 60).toString().padStart(2, "0")}`;

const S = 1.7;                       // 地圖放大係數（史詩感）
const wx = (x) => (x - 50) * S, wz = (y) => (y - 50) * S;
const SIDE = { blue: 0x3b82f6, red: 0xef4444 };
const GLOW = { blue: 0x9ad0ff, red: 0xffb0b0 };

// ── 地形常數（與 LogicEngine.js 一致）──────────────────────────────────────
const LANES = {
  top: [{x:11,y:82},{x:9,y:68},{x:8,y:52},{x:9,y:38},{x:12,y:26},{x:17,y:18},{x:26,y:13},{x:38,y:11},{x:52,y:10},{x:64,y:11},{x:75,y:13},{x:83,y:15}],
  mid: [{x:15,y:85},{x:24,y:76},{x:33,y:67},{x:42,y:58},{x:50,y:50},{x:58,y:42},{x:66,y:34},{x:74,y:26},{x:81,y:19},{x:86,y:15}],
  bot: [{x:15,y:88},{x:30,y:88},{x:45,y:87},{x:60,y:85},{x:73,y:82},{x:82,y:76},{x:87,y:64},{x:89,y:50},{x:89,y:36},{x:88,y:24},{x:86,y:17}],
};
function posOnLane(lane, t) {
  const pts = LANES[lane]; t = clamp(t, 0, 1);
  const seg = (pts.length - 1) * t, i = Math.floor(seg), f = seg - i;
  const a = pts[Math.min(i, pts.length - 1)], b = pts[Math.min(i + 1, pts.length - 1)];
  return { x: lerp(a.x, b.x, f), y: lerp(a.y, b.y, f) };
}
const OBSTACLES = [
  {x:33,y:32,r:6},{x:74,y:73,r:6},
  {x:40,y:40,r:3.5},{x:46,y:46,r:3},{x:52,y:52,r:3},{x:58,y:58,r:3},{x:65,y:66,r:3.5},
  {x:18,y:18,r:3.5},{x:25,y:16,r:3},{x:30,y:20,r:3},{x:22,y:25,r:3},
  {x:14,y:30,r:3},{x:20,y:35,r:3},{x:26,y:30,r:2.8},
  {x:58,y:16,r:3},{x:65,y:18,r:3},{x:72,y:20,r:3},{x:66,y:25,r:3},
  {x:60,y:28,r:2.8},{x:54,y:24,r:2.8},{x:48,y:20,r:2.8},
  {x:18,y:62,r:3},{x:24,y:66,r:3},{x:30,y:70,r:3},{x:22,y:74,r:3},
  {x:16,y:70,r:2.8},{x:34,y:64,r:2.8},{x:38,y:74,r:3},
  {x:68,y:72,r:3},{x:62,y:66,r:3},{x:78,y:68,r:3},{x:82,y:62,r:3},
  {x:70,y:60,r:2.8},{x:64,y:78,r:2.8},{x:58,y:74,r:2.8},
  {x:16,y:46,r:3.5},{x:84,y:54,r:3.5},
  {x:44,y:30,r:2.5},{x:56,y:70,r:2.5},
  {x:42,y:54,r:2.5},{x:58,y:46,r:2.5},
  {x:36,y:48,r:2.5},{x:64,y:52,r:2.5},
];
const WATER = OBSTACLES.slice(0, 7);
const WALLS = OBSTACLES.slice(7);
const PITS = { dragon: { x:74, y:73 }, baron: { x:33, y:32 } };
const BASE = { blue: { x:12, y:90 }, red: { x:87, y:16 } };
const FOUNTAIN = { blue: { x:9, y:93 }, red: { x:91, y:12 } };
const TOWER_T = { blue: [0.15, 0.33, 0.48], red: [0.85, 0.67, 0.52] };
const BUSHES = [
  {x:30,y:42,r:4},{x:70,y:58,r:4},{x:42,y:62,r:3.5},{x:58,y:38,r:3.5},
  {x:20,y:50,r:3},{x:80,y:50,r:3},{x:24,y:80,r:3.5},{x:76,y:20,r:3.5},
  {x:46,y:20,r:3},{x:54,y:80,r:3},
];

// ── 程序化彩色 Rift 底圖（你的圖上傳後即可替換）─────────────────────────────
function makeRiftTexture() {
  const s = 1024, cv = document.createElement("canvas"); cv.width = cv.height = s;
  const g = cv.getContext("2d"), px = (p) => (p / 100) * s;
  // 野區底色（藍方偏冷、紅方偏暖）
  const grad = g.createLinearGradient(0, s, s, 0);
  grad.addColorStop(0, "#2f7d4f"); grad.addColorStop(0.5, "#347a46"); grad.addColorStop(1, "#5a7a36");
  g.fillStyle = grad; g.fillRect(0, 0, s, s);
  // 野區雜訊斑塊
  for (let i = 0; i < 320; i++) {
    g.fillStyle = `rgba(${20+Math.random()*40},${90+Math.random()*70},${40+Math.random()*40},0.18)`;
    const r = 8 + Math.random() * 26;
    g.beginPath(); g.arc(Math.random() * s, Math.random() * s, r, 0, 7); g.fill();
  }
  // 對角河道
  g.strokeStyle = "rgba(70,160,200,0.55)"; g.lineWidth = px(11); g.lineCap = "round";
  g.beginPath(); g.moveTo(px(20), px(20)); g.lineTo(px(80), px(80)); g.stroke();
  g.strokeStyle = "rgba(150,220,245,0.45)"; g.lineWidth = px(4);
  g.beginPath(); g.moveTo(px(20), px(20)); g.lineTo(px(80), px(80)); g.stroke();
  // 三線土路
  for (const lane of ["top", "mid", "bot"]) {
    g.strokeStyle = "rgba(196,170,120,0.85)"; g.lineWidth = px(6.2); g.lineJoin = "round";
    g.beginPath(); LANES[lane].forEach((p, i) => (i ? g.lineTo(px(p.x), px(p.y)) : g.moveTo(px(p.x), px(p.y)))); g.stroke();
    g.strokeStyle = "rgba(150,128,86,0.6)"; g.lineWidth = px(2);
    g.beginPath(); LANES[lane].forEach((p, i) => (i ? g.lineTo(px(p.x), px(p.y)) : g.moveTo(px(p.x), px(p.y)))); g.stroke();
  }
  // 草叢斑塊
  BUSHES.forEach((b) => { g.fillStyle = "rgba(18,70,34,0.6)"; g.beginPath(); g.ellipse(px(b.x), px(b.y), px(b.r), px(b.r * 0.8), 0, 0, 7); g.fill(); });
  // 雙基地
  const baseGlow = (b, c1, c2) => {
    const gr = g.createRadialGradient(px(b.x), px(b.y), px(2), px(b.x), px(b.y), px(11));
    gr.addColorStop(0, c1); gr.addColorStop(1, c2);
    g.fillStyle = gr; g.beginPath(); g.arc(px(b.x), px(b.y), px(11), 0, 7); g.fill();
  };
  baseGlow(BASE.blue, "rgba(120,180,255,0.85)", "rgba(40,90,200,0.05)");
  baseGlow(BASE.red, "rgba(255,150,150,0.85)", "rgba(200,50,50,0.05)");
  const tex = new THREE.CanvasTexture(cv);
  tex.encoding = THREE.sRGBEncoding; tex.anisotropy = 8;
  return tex;
}

// ════════════════════════════════════════════════════════════════════════════
//  LogicEngine —— 對戰大腦（真實 tick 模擬，非假資料）
// ════════════════════════════════════════════════════════════════════════════
const ROLES = ["top", "jungle", "mid", "adc", "sup"];
const ROLE_LANE = { top: "top", jungle: "mid", mid: "mid", adc: "bot", sup: "bot" };
const ROLE_NAME = { top: "上路", jungle: "打野", mid: "中路", adc: "射手", sup: "輔助" };
const TOWER_HP = 1100, NEXUS_HP = 2600;

class LogicEngine {
  constructor(seed = 1) {
    let x = seed | 0; this.rng = () => ((x = (x * 1664525 + 1013904223) & 0xffffffff) >>> 0) / 0xffffffff;
    this.t = 0; this.over = false; this.winner = null;
    this.bK = 0; this.rK = 0; this.bGold = 500; this.rGold = 500;
    this.mid = 0; this.fx = []; this.waveTimer = 0; this.feed = [];

    // 英雄
    this.players = [];
    ["blue", "red"].forEach((side) => {
      ROLES.forEach((role, i) => {
        const tough = [1.6, 1.15, 0.9, 0.8, 1.25][i];
        const power = [30, 34, 36, 42, 18][i];
        const f = FOUNTAIN[side];
        this.players.push({
          id: side[0] + (i + 1), side, role, lane: ROLE_LANE[role],
          pos: { x: f.x + (this.rng() - 0.5) * 6, y: f.y + (this.rng() - 0.5) * 6 },
          maxHp: 600 * tough, hp: 600 * tough, power, tough,
          dead: false, respawn: 0, state: "對線", atkCd: 0, gold: 0,
        });
      });
    });

    // 防禦塔（每線 3 座 + 主堡）
    this.towers = {};
    for (const lane of ["top", "mid", "bot"]) {
      ["blue", "red"].forEach((side) =>
        TOWER_T[side].forEach((t, tier) => {
          this.towers[`${side}_${lane}_${tier}`] = { side, lane, tier, t, pos: posOnLane(lane, t), hp: TOWER_HP, atkCd: 0 };
        }));
    }
    this.towers["blue_nexus"] = { side: "blue", lane: "nexus", tier: 9, pos: BASE.blue, hp: NEXUS_HP, atkCd: 0 };
    this.towers["red_nexus"] = { side: "red", lane: "nexus", tier: 9, pos: BASE.red, hp: NEXUS_HP, atkCd: 0 };

    this.lanes = { top: { bm: [], rm: [] }, mid: { bm: [], rm: [] }, bot: { bm: [], rm: [] } };
    this.dragon = { alive: false, hp: 100, respawn: 90, contested: false };
    this.baron = { alive: false, hp: 100, respawn: 300, contested: false };
    this._mid = 1;
  }

  frontTower(attacker, lane) {
    // attacker 為進攻方 side；回傳該線最前線、且仍存活的敵方塔
    const def = attacker === "blue" ? "red" : "blue";
    const arr = [0, 1, 2].map((tier) => this.towers[`${def}_${lane}_${tier}`]).filter(Boolean);
    arr.sort((a, b) => (attacker === "blue" ? a.t - b.t : b.t - a.t)); // 由近至遠
    return arr.find((tw) => tw.hp > 0) || null;
  }
  laneCleared(side) {
    const def = side === "blue" ? "red" : "blue";
    return ["top", "mid", "bot"].some((ln) => [0, 1, 2].every((tr) => this.towers[`${def}_${ln}_${tr}`].hp <= 0));
  }
  pushFx(f) { this.fx.push({ ...f, exp: f.exp ?? 0.35 }); if (this.fx.length > 60) this.fx.shift(); }

  tick(dt) {
    if (this.over) return;
    this.t += dt;
    const lateFactor = 1 + Math.max(0, this.t - 240) / 240; // 後期傷害放大，避免拖太久

    // ── 小兵成波 ──
    this.waveTimer -= dt;
    if (this.waveTimer <= 0) {
      this.waveTimer = 16;
      for (const ln of ["top", "mid", "bot"]) {
        for (let i = 0; i < 4; i++) {
          if (this.lanes[ln].bm.length < 16) this.lanes[ln].bm.push({ id: "b" + this._mid++, t: 0.06, hp: 130 });
          if (this.lanes[ln].rm.length < 16) this.lanes[ln].rm.push({ id: "r" + this._mid++, t: 0.94, hp: 130 });
        }
      }
    }
    // 小兵移動
    for (const ln of ["top", "mid", "bot"]) {
      this.lanes[ln].bm.forEach((m) => (m.t = Math.min(1, m.t + 0.018 * dt)));
      this.lanes[ln].rm.forEach((m) => (m.t = Math.max(0, m.t - 0.018 * dt)));
      // 小兵交戰
      this.lanes[ln].bm.forEach((b) => {
        const foe = this.lanes[ln].rm.find((r) => Math.abs(r.t - b.t) < 0.035);
        if (foe) { b.hp -= 70 * dt; foe.hp -= 70 * dt; }
      });
      // 推塔
      [["blue", "bm"], ["red", "rm"]].forEach(([side, key]) => {
        const arr = this.lanes[ln][key]; if (!arr.length) return;
        const lead = side === "blue" ? Math.max(...arr.map((m) => m.t)) : Math.min(...arr.map((m) => m.t));
        let tw = this.frontTower(side, ln);
        if (!tw && this.laneCleared(side)) tw = this.towers[(side === "blue" ? "red" : "blue") + "_nexus"];
        if (tw) {
          const reach = side === "blue" ? lead >= tw.t - 0.04 : lead <= tw.t + 0.04;
          if (reach) { tw.hp -= 26 * arr.length * dt * lateFactor; this._dmgGold(side, 0); }
        }
      });
      // 塔反擊小兵
      ["blue", "red"].forEach((side) => {
        for (const tr of [0, 1, 2]) {
          const tw = this.towers[`${side}_${ln}_${tr}`]; if (tw.hp <= 0) continue;
          const enemyKey = side === "blue" ? "rm" : "bm";
          const m = this.lanes[ln][enemyKey].find((mm) => Math.abs(mm.t - tw.t) < 0.05);
          if (m) { m.hp -= 120 * dt; if (this.rng() < dt * 1.5) this.pushFx({ type: "tower", pos: tw.pos, target: posOnLane(ln, m.t), color: SIDE[side] }); }
        }
      });
      // 清除死兵 → 給金
      ["bm", "rm"].forEach((key) => {
        const dead = this.lanes[ln][key].filter((m) => m.hp <= 0).length;
        if (dead) this._dmgGold(key === "bm" ? "red" : "blue", dead * 20);
        this.lanes[ln][key] = this.lanes[ln][key].filter((m) => m.hp > 0);
      });
    }

    // ── 團戰熱點：龍/巴龍坑或聚集點 ──
    const alive = this.players.filter((p) => !p.dead);
    let hot = null;
    if (this.dragon.alive) hot = PITS.dragon;
    if (this.baron.alive) hot = PITS.baron;
    // 也找雙方聚集點
    if (!hot) {
      for (const a of alive) {
        const near = alive.filter((b) => dist(a.pos, b.pos) < 14);
        if (near.filter((b) => b.side !== a.side).length >= 1 && near.length >= 3) {
          hot = { x: near.reduce((s, p) => s + p.pos.x, 0) / near.length, y: near.reduce((s, p) => s + p.pos.y, 0) / near.length };
          break;
        }
      }
    }

    // ── 英雄 AI + 移動 + 戰鬥 ──
    for (const p of this.players) {
      if (p.dead) { p.respawn -= dt; if (p.respawn <= 0) { p.dead = false; p.hp = p.maxHp; const f = FOUNTAIN[p.side]; p.pos = { x: f.x, y: f.y }; p.state = "回防"; } continue; }
      p.atkCd -= dt;
      // 目標決策
      let tgt, st;
      if (p.hp < p.maxHp * 0.25) { tgt = FOUNTAIN[p.side]; st = "撤退"; }
      else if (hot && (p.role === "jungle" || p.role === "sup" || this.rng() < 0.6)) { tgt = hot; st = "團戰!"; }
      else {
        // 對線：往敵方推進方向的線上點
        const lane = p.lane;
        const adv = p.side === "blue" ? clamp(0.35 + this.t / 900, 0.3, 0.7) : clamp(0.65 - this.t / 900, 0.3, 0.7);
        tgt = posOnLane(lane, adv); st = p.role === "jungle" ? "游走" : "對線";
      }
      // 移動
      const d = dist(p.pos, tgt), spd = (st === "團戰!" ? 16 : 13) * dt;
      if (d > 0.6) { p.pos.x += ((tgt.x - p.pos.x) / d) * Math.min(spd, d); p.pos.y += ((tgt.y - p.pos.y) / d) * Math.min(spd, d); }
      // 牆壁避讓
      for (const o of WALLS) { const dd = dist(p.pos, o); if (dd < o.r + 1.4) { p.pos.x += ((p.pos.x - o.x) / (dd || 1)) * (o.r + 1.4 - dd); p.pos.y += ((p.pos.y - o.y) / (dd || 1)) * (o.r + 1.4 - dd); } }
      p.pos.x = clamp(p.pos.x, 3, 97); p.pos.y = clamp(p.pos.y, 3, 97);
      p.state = st;
      // 對敵英雄輸出
      const foe = alive.find((q) => q.side !== p.side && !q.dead && dist(p.pos, q.pos) < 8);
      if (foe) {
        foe.hp -= p.power * dt * 1.1 * lateFactor;
        if (p.atkCd <= 0) { this.pushFx({ type: this.rng() < 0.2 ? "ult" : "line", pos: { ...p.pos }, target: { ...foe.pos }, color: SIDE[p.side] }); p.atkCd = 0.5; }
        if (foe.hp <= 0 && !foe.dead) {
          foe.dead = true; foe.respawn = 6 + Math.min(this.t / 30, 20); foe.hp = 0;
          if (p.side === "blue") this.bK++; else this.rK++;
          this._dmgGold(p.side, 300); p.gold += 300;
          this.feed.unshift({ id: this._mid++, killer: p.id, victim: foe.id, side: p.side, vpos: { x: foe.pos.x, y: foe.pos.y } }); this.feed = this.feed.slice(0, 5);
          this.pushFx({ type: "ult", pos: { ...foe.pos }, color: 0xfbbf24, exp: 0.6 });
        }
      }
      // 英雄拆塔（在敵塔旁且附近無敵人）
      const tw = this.frontTower(p.side, p.lane);
      if (tw && dist(p.pos, tw.pos) < 6 && !alive.some((q) => q.side !== p.side && dist(q.pos, tw.pos) < 9)) tw.hp -= 40 * dt * lateFactor;
    }

    // ── 防禦塔/水晶死亡給金 ──
    for (const k in this.towers) { const tw = this.towers[k]; if (tw.hp <= 0 && !tw._dead) { tw._dead = true; this._dmgGold(tw.side === "blue" ? "red" : "blue", tw.lane === "nexus" ? 0 : 250); } }

    // ── 大型目標 ──
    const upd = (o, key, gold) => {
      if (!o.alive) { o.respawn -= dt; if (o.respawn <= 0) { o.alive = true; o.hp = 100; } return; }
      const pit = PITS[key]; const b = alive.filter((p) => p.side === "blue" && dist(p.pos, pit) < 9).length;
      const r = alive.filter((p) => p.side === "red" && dist(p.pos, pit) < 9).length;
      o.contested = b > 0 && r > 0;
      if (b > r) { o.hp -= 28 * dt; if (o.hp <= 0) { o.alive = false; o.respawn = 150; this._dmgGold("blue", gold); } }
      else if (r > b) { o.hp -= 28 * dt; if (o.hp <= 0) { o.alive = false; o.respawn = 150; this._dmgGold("red", gold); } }
    };
    if (this.t > 90) upd(this.dragon, "dragon", 200);
    if (this.t > 300) upd(this.baron, "baron", 400);

    // 被動金 + fx 衰減
    this.bGold += 14 * dt; this.rGold += 14 * dt;
    this.fx = this.fx.filter((f) => (f.exp -= dt) > 0);

    // 勝負
    if (this.towers.blue_nexus.hp <= 0) { this.over = true; this.winner = "red"; }
    if (this.towers.red_nexus.hp <= 0) { this.over = true; this.winner = "blue"; }
  }
  _dmgGold(side, g) { if (side === "blue") this.bGold += g; else this.rGold += g; }

  snapshot() {
    const gd = this.bGold - this.rGold;
    const tw = (s) => Object.values(this.towers).filter((t) => t.side === s && t.lane !== "nexus" && t.hp <= 0).length;
    const winProb = clamp(0.5 + gd / 14000 + (tw("red") - tw("blue")) * 0.05, 0.05, 0.95);
    return {
      ts: this.t,
      players: this.players.map((p) => ({ id: p.id, side: p.side, role: p.role, pos: { ...p.pos }, hp: clamp(p.hp / p.maxHp, 0, 1), dead: p.dead, respawn: p.respawn, state: p.state })),
      towers: Object.fromEntries(Object.entries(this.towers).map(([k, t]) => [k, { side: t.side, lane: t.lane, tier: t.tier, pos: t.pos, hp: clamp(t.hp / (t.lane === "nexus" ? NEXUS_HP : TOWER_HP), 0, 1) }])),
      lanes: { top: this._snapLane("top"), mid: this._snapLane("mid"), bot: this._snapLane("bot") },
      dragon: { ...this.dragon }, baron: { ...this.baron },
      fx: this.fx.map((f) => ({ ...f })), feed: this.feed.slice(),
      bK: this.bK, rK: this.rK, bGold: this.bGold, rGold: this.rGold, winProb, over: this.over, winner: this.winner,
    };
  }
  _snapLane(ln) {
    return { bm: this.lanes[ln].bm.map((m) => ({ id: m.id, t: m.t })), rm: this.lanes[ln].rm.map((m) => ({ id: m.id, t: m.t })) };
  }
}

// ════════════════════════════════════════════════════════════════════════════
//  useGameStore（內聯 zustand 相容）+ useLocalServer（驅動水管）
// ════════════════════════════════════════════════════════════════════════════
function createStore(init) {
  let state = init; const subs = new Set();
  return {
    getState: () => state,
    setState: (p) => { state = { ...state, ...(typeof p === "function" ? p(state) : p) }; subs.forEach((f) => f()); },
    subscribe: (f) => { subs.add(f); return () => subs.delete(f); },
  };
}
const _boot = new LogicEngine(1).snapshot();
const store = createStore({
  prev: _boot, snapshot: _boot, subTRef: { current: 0 },
  hud: { ts: 0, bK: 0, rK: 0, bGold: 500, rGold: 500, winProb: 0.5, over: false, winner: null, feed: [] },
});
function pushFrame(snap) {
  const s = store.getState();
  store.setState({ prev: s.snapshot, snapshot: snap, hud: { ts: snap.ts, bK: snap.bK, rK: snap.rK, bGold: snap.bGold, rGold: snap.rGold, winProb: snap.winProb, over: snap.over, winner: snap.winner, feed: snap.feed } });
  s.subTRef.current = 0;
}

const TICK_MS = 130, DT_SIM = 0.5; // 每 130ms tick 一次、每 tick 推進 0.5 模擬秒（約 3.8x）
function useLocalServer(battleConfig) {
  const engineRef = useRef(null);
  const intervalRef = useRef(null), rafRef = useRef(null), lastTick = useRef(0);
  const [playing, setPlaying] = useState(false);

  const stop = useCallback(() => {
    clearInterval(intervalRef.current); cancelAnimationFrame(rafRef.current);
    intervalRef.current = null; rafRef.current = null; setPlaying(false);
  }, []);

  const start = useCallback(() => {
    stop();
    const eng = new LogicEngine((Date.now() & 0xffff) | 1); engineRef.current = eng;
    // Phase 9：平台 roster 資料流注入點。目前 LogicEngine 未開放注入口 → 正式回報
    // no-op（不改 seed、不改 tick、不改演算法）；資料流已就緒，等引擎支援即接通。
    applyRosterToEngine(eng, buildEngineSlots(battleConfig || null));
    const boot = eng.snapshot(); pushFrame(boot); pushFrame(boot);
    lastTick.current = performance.now();
    intervalRef.current = setInterval(() => {
      eng.tick(DT_SIM); pushFrame(eng.snapshot()); lastTick.current = performance.now();
      if (eng.over) stop();
    }, TICK_MS);
    const subT = store.getState().subTRef;
    const loop = () => { subT.current = clamp((performance.now() - lastTick.current) / TICK_MS, 0, 1); rafRef.current = requestAnimationFrame(loop); };
    rafRef.current = requestAnimationFrame(loop);
    setPlaying(true);
  }, [stop, battleConfig]);

  useEffect(() => () => stop(), [stop]);
  return { playing, start, stop };
}

// ── three 膠囊（r128 無 CapsuleGeometry）──────────────────────────────────────
function makeCapsule(radius, length, mat) {
  const grp = new THREE.Group();
  const cyl = new THREE.Mesh(new THREE.CylinderGeometry(radius, radius, length, 18), mat); cyl.castShadow = true;
  const top = new THREE.Mesh(new THREE.SphereGeometry(radius, 18, 12), mat); top.position.y = length / 2; top.castShadow = true;
  const bot = new THREE.Mesh(new THREE.SphereGeometry(radius, 18, 12), mat); bot.position.y = -length / 2; bot.castShadow = true;
  grp.add(cyl, top, bot); return grp;
}
// 文字精靈（永遠面向鏡頭；職業標籤 / 擊殺浮字共用）
function makeLabelSprite(text, hex, sx = 3, sy = 1.5) {
  const c = document.createElement("canvas"); c.width = 128; c.height = 64;
  const g = c.getContext("2d");
  g.font = "bold 44px system-ui,sans-serif"; g.textAlign = "center"; g.textBaseline = "middle";
  g.lineWidth = 7; g.strokeStyle = "rgba(0,0,0,0.85)"; g.strokeText(text, 64, 34);
  g.fillStyle = "#" + hex.toString(16).padStart(6, "0"); g.fillText(text, 64, 34);
  const tex = new THREE.CanvasTexture(c); tex.encoding = THREE.sRGBEncoding;
  const sp = new THREE.Sprite(new THREE.SpriteMaterial({ map: tex, transparent: true, depthTest: false }));
  sp.scale.set(sx * S, sy * S, 1); return sp;
}
// 職業辨識頂飾
function makeTopper(role, color) {
  const mat = new THREE.MeshStandardMaterial({ color, emissive: color, emissiveIntensity: 0.85, roughness: 0.2, metalness: 0.85 });
  let g, flat = false;
  if (role === "adc") g = new THREE.ConeGeometry(0.34 * S, 1.9 * S, 4);
  else if (role === "mid") g = new THREE.SphereGeometry(0.55 * S, 12, 12);
  else if (role === "jungle") g = new THREE.TetrahedronGeometry(0.75 * S);
  else if (role === "sup") { g = new THREE.TorusGeometry(0.6 * S, 0.17 * S, 8, 18); flat = true; }
  else g = new THREE.BoxGeometry(1.7 * S, 0.5 * S, 0.95 * S);
  const m = new THREE.Mesh(g, mat); if (flat) m.rotation.x = Math.PI / 2; m.castShadow = true; return m;
}

// ════════════════════════════════════════════════════════════════════════════
//  GameView / App —— 3D 渲染殼（只讀 store）
// ════════════════════════════════════════════════════════════════════════════
export default function App({ battleConfig } = {}) {
  const mountRef = useRef(null);
  const miniRef = useRef(null);
  const autoRef = useRef(true);
  const [auto, setAuto] = useState(true);
  const { playing, start, stop } = useLocalServer(battleConfig);
  useEffect(() => { autoRef.current = auto; }, [auto]);

  // HUD 隨 store 更新（不影響 3D 內插）
  const hud = React.useSyncExternalStore(store.subscribe, () => store.getState().hud);

  useEffect(() => {
    const mount = mountRef.current; if (!mount) return;
    const W = () => mount.clientWidth, H = () => mount.clientHeight;

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(W(), H());
    renderer.shadowMap.enabled = true; renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.outputEncoding = THREE.sRGBEncoding;
    renderer.toneMapping = THREE.ACESFilmicToneMapping; renderer.toneMappingExposure = 1.35;
    mount.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x0d1420);
    scene.fog = new THREE.Fog(0x0d1420, 260 * S, 460 * S);

    // 鏡頭：放大後的斜對角神之視角
    const VIEW = 165 * S;
    const cam = new THREE.OrthographicCamera(-VIEW / 2, VIEW / 2, VIEW / 2, -VIEW / 2, 0.1, 1200);
    cam.zoom = 1.0;
    let theta = 0.8, phi = 0.74, R = 360 * S;
    const placeCam = () => { cam.position.set(R * Math.sin(phi) * Math.sin(theta), R * Math.cos(phi), R * Math.sin(phi) * Math.cos(theta)); cam.lookAt(0, 0, 0); };
    const setFrustum = () => { const a = W() / H(); cam.left = -VIEW * a / 2; cam.right = VIEW * a / 2; cam.top = VIEW / 2; cam.bottom = -VIEW / 2; cam.updateProjectionMatrix(); };
    setFrustum(); placeCam();

    // ── 全面調亮：強環境光 + 強方向光 + 半球補光 ──
    scene.add(new THREE.AmbientLight(0xffffff, 1.15));
    scene.add(new THREE.HemisphereLight(0xcfe6ff, 0x415028, 0.85));
    const sun = new THREE.DirectionalLight(0xfff4e0, 2.7);
    sun.position.set(60 * S, 150 * S, 50 * S); sun.castShadow = true;
    sun.shadow.mapSize.set(2048, 2048);
    Object.assign(sun.shadow.camera, { left: -110 * S, right: 110 * S, top: 110 * S, bottom: -110 * S, near: 1, far: 500 * S });
    sun.shadow.bias = -0.0004; sun.shadow.camera.updateProjectionMatrix(); scene.add(sun);
    const fill = new THREE.DirectionalLight(0x9ec8ff, 0.6); fill.position.set(-50 * S, 60 * S, -40 * S); scene.add(fill);

    // ── 地板（明亮、不反光）──
    const loadFloorTex = (cb) => {
      if (MOBA_MAP_DATAURI) new THREE.TextureLoader().load(MOBA_MAP_DATAURI, (t) => { t.encoding = THREE.sRGBEncoding; t.anisotropy = 8; cb(t); });
      else cb(makeRiftTexture());
    };
    const floorMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 1.0, metalness: 0.0 });
    const floor = new THREE.Mesh(new THREE.PlaneGeometry(100 * S, 100 * S), floorMat);
    floor.rotation.x = -Math.PI / 2; floor.receiveShadow = true; scene.add(floor);
    loadFloorTex((t) => { floorMat.map = t; floorMat.needsUpdate = true; });

    // ── 河道：半透明水體 + 起伏石塊 ──
    WATER.forEach((o) => {
      const w = new THREE.Mesh(new THREE.CircleGeometry(o.r * S, 40),
        new THREE.MeshStandardMaterial({ color: 0x2b6f9e, emissive: 0x1d6fa0, emissiveIntensity: 0.3, transparent: true, opacity: 0.6, roughness: 0.2, metalness: 0.3 }));
      w.rotation.x = -Math.PI / 2; w.position.set(wx(o.x), 0.05, wz(o.y)); w.receiveShadow = true; scene.add(w);
    });
    // 河道/野區隨機起伏石塊（高低層次）
    const rockMat = new THREE.MeshStandardMaterial({ color: 0x6d7689, roughness: 0.85, metalness: 0.15, flatShading: true });
    const rng = (() => { let x = 7; return () => ((x = (x * 1103515245 + 12345) & 0x7fffffff) / 0x7fffffff); })();
    for (let i = 0; i < 46; i++) {
      const ang = rng() * 7, rad = (18 + rng() * 30);
      const cx = 50 + Math.cos(ang) * rad - 0, cy = 50 + Math.sin(ang) * rad;
      const h = (1.2 + rng() * 3) * S;
      const m = new THREE.Mesh(new THREE.DodecahedronGeometry((0.8 + rng() * 1.8) * S, 0), rockMat);
      m.position.set(wx(clamp(cx, 5, 95)), h * 0.3, wz(clamp(cy, 5, 95)));
      m.rotation.set(rng() * 3, rng() * 3, rng() * 3); m.scale.y = 0.6 + rng(); m.castShadow = true; m.receiveShadow = true;
      scene.add(m);
    }

    // ── 立體石牆（OBSTACLES 垂直拉伸，多面有起伏）──
    const wallMat = new THREE.MeshStandardMaterial({ color: 0x5a6478, roughness: 0.8, metalness: 0.18, flatShading: true });
    WALLS.forEach((o) => {
      const h = (2.2 + o.r * 0.9) * S;
      const m = new THREE.Mesh(new THREE.CylinderGeometry(o.r * 0.85 * S, o.r * S, h, 7), wallMat);
      m.position.set(wx(o.x), h / 2, wz(o.y)); m.castShadow = true; m.receiveShadow = true; scene.add(m);
      // 頂部小石塊增加起伏
      const cap = new THREE.Mesh(new THREE.DodecahedronGeometry(o.r * 0.5 * S, 0), wallMat);
      cap.position.set(wx(o.x), h + o.r * 0.3 * S, wz(o.y)); cap.castShadow = true; scene.add(cap);
    });

    // ── 會動草叢 ──
    const blades = [];
    BUSHES.forEach((b, bi) => {
      const grp = new THREE.Group(); grp.position.set(wx(b.x), 0, wz(b.y));
      const n = Math.max(7, Math.round(b.r * 3)), cols = [0x2aa14e, 0x37c065, 0x1f8a42, 0x46d47a];
      for (let i = 0; i < n; i++) {
        const a = (i / n) * 7 + bi, rr = b.r * (0.25 + rng() * 0.7) * S, hh = (1.4 + rng() * 1.6) * S;
        const leaf = new THREE.Mesh(new THREE.ConeGeometry(0.5 * S, hh, 5),
          new THREE.MeshStandardMaterial({ color: cols[i % 4], roughness: 0.75, metalness: 0.05, flatShading: true }));
        leaf.position.set(Math.cos(a) * rr, hh / 2, Math.sin(a) * rr); leaf.castShadow = true; leaf.userData.ph = rng() * 7;
        grp.add(leaf); blades.push(leaf);
      }
      scene.add(grp);
    });

    // ── 防禦塔（多層次圓柱）+ 巨大主堡水晶 ──
    const towerObjs = {};
    Object.entries(store.getState().snapshot.towers).forEach(([key, t]) => {
      const isNexus = t.lane === "nexus", col = SIDE[t.side], glow = GLOW[t.side];
      const grp = new THREE.Group(); grp.position.set(wx(t.pos.x), 0, wz(t.pos.y));
      const sc = (isNexus ? 1 : 0.62);
      // 三層塔身（高低層次）
      const tiers = [
        { r: 3.0, h: 4.0, y: 2.0, c: 0x7d8696 },
        { r: 2.2, h: 4.6, y: 6.3, c: col },
        { r: 1.6, h: 3.0, y: 10.3, c: 0x9aa6ba },
      ];
      tiers.forEach((ti) => {
        const m = new THREE.Mesh(new THREE.CylinderGeometry(ti.r * sc * S, (ti.r + 0.4) * sc * S, ti.h * sc * S, 8),
          new THREE.MeshStandardMaterial({ color: ti.c, emissive: ti.c === col ? col : 0x000000, emissiveIntensity: ti.c === col ? 0.45 : 0, roughness: 0.5, metalness: 0.55 }));
        m.position.y = ti.y * sc * S; m.castShadow = true; m.receiveShadow = true; grp.add(m);
      });
      // 水晶（主堡巨大）
      const crySize = (isNexus ? 4.6 : 1.4) * S;
      const crystal = new THREE.Mesh(new THREE.OctahedronGeometry(crySize, 0),
        new THREE.MeshStandardMaterial({ color: glow, emissive: glow, emissiveIntensity: isNexus ? 1.9 : 1.3, roughness: 0.1, metalness: 0.35 }));
      crystal.position.y = (isNexus ? 16 : 13.5) * sc * S; crystal.castShadow = true; grp.add(crystal);
      grp.add(new THREE.PointLight(glow, isNexus ? 9 : 2.2, (isNexus ? 60 : 26) * S));
      // 廢墟（死亡時顯示）
      const stump = new THREE.Mesh(new THREE.CylinderGeometry(2.4 * sc * S, 3.0 * sc * S, 2.0 * sc * S, 7),
        new THREE.MeshStandardMaterial({ color: 0x33363d, roughness: 1, metalness: 0.1, flatShading: true }));
      stump.position.y = 1.0 * sc * S; stump.visible = false; stump.castShadow = true; grp.add(stump);
      // 塔血條（面向鏡頭）
      const hpBar = new THREE.Group(); hpBar.position.y = (isNexus ? 22 : 15) * sc * S;
      const hbg = new THREE.Mesh(new THREE.PlaneGeometry((isNexus ? 6 : 3.2) * S, 0.5 * S), new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.7, depthTest: false })); hbg.position.z = -0.01;
      const hfgMat = new THREE.MeshBasicMaterial({ color: t.side === "blue" ? 0x60a5fa : 0xf87171, depthTest: false });
      const hfg = new THREE.Mesh(new THREE.PlaneGeometry((isNexus ? 5.8 : 3.0) * S, 0.38 * S), hfgMat);
      hpBar.add(hbg, hfg); grp.add(hpBar);
      scene.add(grp);
      towerObjs[key] = { grp, crystal, stump, isNexus, hpBar, hfg, hfgW: (isNexus ? 5.8 : 3.0) * S };
    });

    // ── 龍/巴龍坑圖騰 ──
    const obj3d = {};
    [["dragon", PITS.dragon, 0xb794f6], ["baron", PITS.baron, 0xfbbf24]].forEach(([k, pit, col]) => {
      const m = new THREE.Mesh(new THREE.IcosahedronGeometry(2.6 * S, 0),
        new THREE.MeshStandardMaterial({ color: col, emissive: col, emissiveIntensity: 1.4, roughness: 0.3, metalness: 0.6 }));
      m.position.set(wx(pit.x), 2.0 * S, wz(pit.y)); m.castShadow = true; m.visible = false; scene.add(m);
      const pl = new THREE.PointLight(col, 3, 24 * S); pl.position.copy(m.position); pl.visible = false; scene.add(pl);
      obj3d[k] = { mesh: m, light: pl };
    });

    // ── 英雄（建池，固定 10）──
    const heroObjs = {};
    store.getState().snapshot.players.forEach((p) => {
      const col = SIDE[p.side], glow = GLOW[p.side];
      const root = new THREE.Group(); root.position.set(wx(p.pos.x), 0, wz(p.pos.y));
      const mat = new THREE.MeshStandardMaterial({ color: col, emissive: col, emissiveIntensity: 0.65, roughness: 0.3, metalness: 0.7 });
      const cap = makeCapsule(1.0 * S, 2.0 * S, mat); cap.position.y = 1.7 * S; root.add(cap);
      const ringMat = new THREE.MeshBasicMaterial({ color: glow, transparent: true, opacity: 0.6, side: THREE.DoubleSide });
      const ring = new THREE.Mesh(new THREE.RingGeometry(1.5 * S, 2.0 * S, 32), ringMat); ring.rotation.x = -Math.PI / 2; ring.position.y = 0.08; root.add(ring);
      const hpGrp = new THREE.Group(); hpGrp.position.y = 4.0 * S;
      const bg = new THREE.Mesh(new THREE.PlaneGeometry(2.6 * S, 0.4 * S), new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.75 })); bg.position.z = -0.01;
      const fgMat = new THREE.MeshBasicMaterial({ color: 0x34d399 });
      const fg = new THREE.Mesh(new THREE.PlaneGeometry(2.5 * S, 0.3 * S), fgMat);
      hpGrp.add(bg, fg); root.add(hpGrp);
      const topper = makeTopper(p.role, glow); topper.position.y = 3.4 * S; root.add(topper);
      const label = makeLabelSprite(ROLE_NAME[p.role][0], p.side === "blue" ? 0x93c5fd : 0xfca5a5, 2.4, 1.2); label.position.y = 4.9 * S; root.add(label);
      scene.add(root);
      heroObjs[p.id] = { root, cap, mat, ring, ringMat, hpGrp, fg, fgMat, topper, seed: Math.random() * 7 };
    });

    // ── 小兵池 + fx 群組 + 擊殺浮字 ──
    const minionMeshes = new Map();
    const fxGroup = new THREE.Group(); scene.add(fxGroup);
    const killGroup = new THREE.Group(); scene.add(killGroup);
    const killSprites = []; const seenFeed = new Set();

    // 互動
    let dragging = false, lx = 0, ly = 0; const dom = renderer.domElement;
    const onDown = (e) => { dragging = true; lx = e.clientX; ly = e.clientY; };
    const onMove = (e) => { if (!dragging) return; theta -= (e.clientX - lx) * 0.006; phi = clamp(phi - (e.clientY - ly) * 0.006, 0.16, 1.4); lx = e.clientX; ly = e.clientY; placeCam(); };
    const onUp = () => { dragging = false; };
    const onWheel = (e) => { e.preventDefault(); cam.zoom = clamp(cam.zoom * (e.deltaY < 0 ? 1.1 : 0.9), 0.4, 4); cam.updateProjectionMatrix(); };
    dom.addEventListener("pointerdown", onDown); window.addEventListener("pointermove", onMove); window.addEventListener("pointerup", onUp);
    dom.addEventListener("wheel", onWheel, { passive: false });
    const onResize = () => { renderer.setSize(W(), H()); setFrustum(); };
    window.addEventListener("resize", onResize);

    // ── 小地圖繪製 ──
    const drawMini = (snap, vis) => {
      const cv = miniRef.current; if (!cv) return;
      const g = cv.getContext("2d"), D = cv.width, P = (v) => (v / 100) * D;
      g.clearRect(0, 0, D, D);
      g.fillStyle = "rgba(10,18,28,0.82)"; g.fillRect(0, 0, D, D);
      g.strokeStyle = "rgba(70,150,200,0.5)"; g.lineWidth = D * 0.05; g.beginPath(); g.moveTo(P(20), P(20)); g.lineTo(P(80), P(80)); g.stroke();
      g.strokeStyle = "rgba(190,170,120,0.4)"; g.lineWidth = 2;
      for (const ln of ["top", "mid", "bot"]) { g.beginPath(); LANES[ln].forEach((p, i) => (i ? g.lineTo(P(p.x), P(p.y)) : g.moveTo(P(p.x), P(p.y)))); g.stroke(); }
      Object.values(snap.towers).forEach((t) => { if (t.hp <= 0) return; g.fillStyle = t.side === "blue" ? "#3b82f6" : "#ef4444"; const s = t.lane === "nexus" ? 6 : 3.4; g.fillRect(P(t.pos.x) - s / 2, P(t.pos.y) - s / 2, s, s); });
      [["dragon", PITS.dragon, "#b794f6"], ["baron", PITS.baron, "#fbbf24"]].forEach(([k, pit, c]) => { if (!snap[k].alive) return; g.fillStyle = c; g.beginPath(); g.arc(P(pit.x), P(pit.y), 3, 0, 7); g.fill(); });
      snap.players.forEach((p) => {
        if (p.dead) return; if (p.side === "red" && !vis(p.pos)) return;
        g.fillStyle = p.side === "blue" ? "#93c5fd" : "#fca5a5";
        g.beginPath(); g.arc(P(p.pos.x), P(p.pos.y), 3.4, 0, 7); g.fill();
        g.strokeStyle = "rgba(0,0,0,0.7)"; g.lineWidth = 1; g.stroke();
      });
    };

    // ── 渲染迴圈（等同 useFrame；只讀 store，內插不重繪）──
    let raf, lastNow = performance.now();
    const tick = (now) => {
      const dt = Math.min((now - lastNow) / 1000, 0.05); lastNow = now;
      const { prev, snapshot, subTRef } = store.getState();
      const a = ease(clamp(subTRef.current, 0, 1));
      const nextHero = {}; snapshot.players.forEach((p) => (nextHero[p.id] = p));
      // 戰爭迷霧：藍方（德國海豹）視野來源 = 存活藍英雄 + 存活藍塔
      const VIS = [];
      snapshot.players.forEach((p) => { if (p.side === "blue" && !p.dead) VIS.push(p.pos); });
      Object.values(snapshot.towers).forEach((t) => { if (t.side === "blue" && t.hp > 0) VIS.push(t.pos); });
      const vis = (pos, r = 17) => VIS.some((v) => (v.x - pos.x) ** 2 + (v.y - pos.y) ** 2 < r * r);

      // 英雄
      prev.players.forEach((p) => {
        const o = heroObjs[p.id]; if (!o) return;
        const np = nextHero[p.id] || p;
        o.root.position.x = lerp(wx(p.pos.x), wx(np.pos.x), a);
        o.root.position.z = lerp(wz(p.pos.y), wz(np.pos.y), a);
        const dx = wx(np.pos.x) - wx(p.pos.x), dz = wz(np.pos.y) - wz(p.pos.y);
        if (dx * dx + dz * dz > 1e-4) o.root.rotation.y = Math.atan2(dx, dz);
        const dead = p.dead;
        o.cap.scale.y = dead ? 0.25 : 1; o.cap.position.y = dead ? 0.4 * S : 1.7 * S + Math.sin(now / 1000 * 3 + o.seed) * 0.07 * S;
        o.mat.color.setHex(dead ? 0x3a3a3a : SIDE[p.side]); o.mat.emissiveIntensity = dead ? 0 : 0.65;
        o.ringMat.opacity = dead ? 0.12 : 0.6;
        o.hpGrp.visible = !dead; o.hpGrp.quaternion.copy(cam.quaternion);
        const hp = clamp(p.hp, 0.001, 1); o.fg.scale.x = hp; o.fg.position.x = -(2.5 * S * (1 - hp)) / 2;
        o.fgMat.color.setHex(hp > 0.55 ? 0x34d399 : hp > 0.28 ? 0xfbbf24 : 0xf87171);
        o.topper.visible = !dead; o.topper.rotation.y += dt * 1.2; o.topper.position.y = 3.4 * S + Math.sin(now / 1000 * 3 + o.seed) * 0.07 * S;
        // 戰爭迷霧：敵方（紅）僅在藍方視野內可見
        o.root.visible = p.side === "blue" ? true : vis(np.pos);
      });

      // 小兵（依 id 同步增刪 + 內插）
      const seen = new Set();
      const nextMin = {};
      ["top", "mid", "bot"].forEach((ln) => { ["bm", "rm"].forEach((k) => snapshot.lanes[ln][k].forEach((m) => (nextMin[k[0] + ":" + ln + ":" + m.id] = m.t))); });
      ["top", "mid", "bot"].forEach((ln) => {
        [["bm", "blue"], ["rm", "red"]].forEach(([k, side]) => {
          prev.lanes[ln][k].forEach((m) => {
            const key = k[0] + ":" + ln + ":" + m.id; seen.add(key);
            let mesh = minionMeshes.get(key);
            if (!mesh) {
              mesh = new THREE.Mesh(new THREE.CylinderGeometry(0.4 * S, 0.52 * S, 1.3 * S, 6),
                new THREE.MeshStandardMaterial({ color: SIDE[side], emissive: SIDE[side], emissiveIntensity: 0.4, roughness: 0.4, metalness: 0.6 }));
              mesh.castShadow = true; minionMeshes.set(key, mesh); scene.add(mesh);
            }
            const tt = lerp(m.t, nextMin[key] ?? m.t, a), p = posOnLane(ln, tt);
            mesh.position.set(wx(p.x), 0.65 * S, wz(p.y));
            mesh.visible = side === "blue" ? true : vis(p, 14);
          });
        });
      });
      minionMeshes.forEach((mesh, key) => { if (!seen.has(key)) { scene.remove(mesh); mesh.geometry.dispose(); mesh.material.dispose(); minionMeshes.delete(key); } });

      // 塔狀態
      Object.entries(snapshot.towers).forEach(([key, t]) => {
        const o = towerObjs[key]; if (!o) return;
        const dead = t.hp <= 0;
        o.crystal.visible = !dead; o.grp.children.forEach((c) => { if (c !== o.stump && c !== o.hpBar) c.visible = !dead; }); o.stump.visible = dead;
        o.hpBar.visible = !dead; o.hpBar.quaternion.copy(cam.quaternion);
        o.hfg.scale.x = clamp(t.hp, 0.001, 1); o.hfg.position.x = -(o.hfgW * (1 - clamp(t.hp, 0, 1))) / 2;
        if (!dead) { o.crystal.rotation.y += dt * (o.isNexus ? 0.5 : 1.0); if (o.isNexus) o.crystal.scale.setScalar(1 + Math.sin(now / 1000 * 2) * 0.06); }
      });

      // 目標
      [["dragon"], ["baron"]].forEach(([k]) => {
        const d = snapshot[k], o = obj3d[k]; o.mesh.visible = d.alive; o.light.visible = d.alive;
        if (d.alive) { o.mesh.rotation.y += dt * 0.7; o.mesh.material.emissiveIntensity = d.contested ? 2.6 : 1.4; }
      });

      // fx 重建
      while (fxGroup.children.length) { const c = fxGroup.children.pop(); c.geometry?.dispose?.(); c.material?.dispose?.(); }
      snapshot.fx.forEach((f) => {
        if (!vis(f.pos, 22)) return; // 迷霧外的交火不顯示
        const maxLife = f.type === "ult" ? 0.6 : 0.35, ratio = clamp(f.exp / maxLife, 0, 1);
        if (f.type === "line" || f.type === "tower") {
          const A = new THREE.Vector3(wx(f.pos.x), 1.2 * S, wz(f.pos.y)), B = new THREE.Vector3(wx(f.target.x), 1.2 * S, wz(f.target.y));
          const len = A.distanceTo(B); if (len < 0.01) return;
          const rad = (0.1 + 0.18 * ratio) * S;
          const m = new THREE.Mesh(new THREE.CylinderGeometry(rad * 0.4, rad, len, 6), new THREE.MeshStandardMaterial({ color: f.color, emissive: f.color, emissiveIntensity: 2.6, transparent: true, opacity: 0.35 + 0.65 * ratio }));
          m.position.copy(A.clone().add(B).multiplyScalar(0.5)); m.quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), B.clone().sub(A).normalize()); fxGroup.add(m);
        } else if (f.type === "ult") {
          const grow = 1 - ratio, rout = (1.2 + grow * 4.5) * S;
          const ring = new THREE.Mesh(new THREE.RingGeometry(rout * 0.62, rout, 36), new THREE.MeshBasicMaterial({ color: f.color, transparent: true, opacity: 0.7 * ratio, side: THREE.DoubleSide }));
          ring.rotation.x = -Math.PI / 2; ring.position.set(wx(f.pos.x), 0.3, wz(f.pos.y)); fxGroup.add(ring);
          const core = new THREE.Mesh(new THREE.SphereGeometry(1.6 * S * ratio + 0.3, 14, 14), new THREE.MeshStandardMaterial({ color: f.color, emissive: f.color, emissiveIntensity: 2.4, transparent: true, opacity: ratio }));
          core.position.set(wx(f.pos.x), 1.6 * S, wz(f.pos.y)); fxGroup.add(core);
        } else {
          const orb = new THREE.Mesh(new THREE.SphereGeometry(1.4 * S, 16, 16), new THREE.MeshStandardMaterial({ color: f.color, emissive: f.color, emissiveIntensity: 2.2, transparent: true, opacity: 0.85 * ratio }));
          orb.position.set(wx(f.pos.x), 1.6 * S, wz(f.pos.y)); fxGroup.add(orb);
        }
      });

      // 擊殺浮字（新進 feed → 在死亡位置升起淡出）
      snapshot.feed.forEach((k) => {
        if (seenFeed.has(k.id) || !k.vpos) return; seenFeed.add(k.id);
        const sp = makeLabelSprite("💀", 0xffffff, 3.4, 3.4); sp.position.set(wx(k.vpos.x), 3 * S, wz(k.vpos.y));
        sp.userData.born = now; killGroup.add(sp); killSprites.push(sp);
      });
      for (let i = killSprites.length - 1; i >= 0; i--) {
        const sp = killSprites[i], age = (now - sp.userData.born) / 1000;
        if (age > 1.6) { killGroup.remove(sp); sp.material.map.dispose(); sp.material.dispose(); killSprites.splice(i, 1); continue; }
        sp.position.y = 3 * S + age * 4 * S; sp.material.opacity = clamp(1 - age / 1.6, 0, 1);
      }

      drawMini(snapshot, vis);

      // 草叢 / 鏡頭
      const t = now / 1000;
      blades.forEach((l) => { l.rotation.z = Math.sin(t * 1.6 + l.userData.ph) * 0.18; l.rotation.x = Math.cos(t * 1.2 + l.userData.ph) * 0.12; });
      if (autoRef.current) { theta += dt * 0.1; placeCam(); }

      renderer.render(scene, cam);
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);

    return () => {
      cancelAnimationFrame(raf);
      dom.removeEventListener("pointerdown", onDown); window.removeEventListener("pointermove", onMove); window.removeEventListener("pointerup", onUp);
      dom.removeEventListener("wheel", onWheel); window.removeEventListener("resize", onResize);
      scene.traverse((o) => { if (o.geometry) o.geometry.dispose(); if (o.material) (Array.isArray(o.material) ? o.material : [o.material]).forEach((m) => m.dispose()); });
      renderer.dispose(); if (dom.parentNode) dom.parentNode.removeChild(dom);
    };
  }, []);

  const blueLead = hud.bGold >= hud.rGold;
  return (
    <div style={{ position: "relative", width: "100%", height: "min(82vh, 720px)", background: "#0d1420", borderRadius: 14, overflow: "hidden", fontFamily: "system-ui,-apple-system,sans-serif" }}>
      <div ref={mountRef} style={{ position: "absolute", inset: 0, cursor: "grab" }} />

      {/* 比分列 */}
      <div style={{ position: "absolute", top: 10, left: 10, right: 10, display: "flex", justifyContent: "space-between", alignItems: "center", pointerEvents: "none", gap: 8 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, background: "rgba(8,14,24,0.7)", border: "1px solid rgba(59,130,246,0.5)", borderRadius: 10, padding: "5px 11px", backdropFilter: "blur(4px)" }}>
          <span style={{ fontSize: 15 }}>🦭</span><span style={{ color: "#93c5fd", fontWeight: 800, fontSize: 13 }}>德國海豹</span>
          <span style={{ color: "#fff", fontWeight: 900, fontSize: 18, fontFamily: "monospace" }}>{hud.bK}</span>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ color: "#fff", fontSize: 16, fontWeight: 900, fontFamily: "monospace", background: "rgba(8,14,24,0.7)", padding: "2px 12px", borderRadius: 8 }}>{fmtT(hud.ts)}</div>
          <div style={{ color: "#fbbf24", fontSize: 10, fontWeight: 800, marginTop: 2 }}>金幣差 {blueLead ? "🔵" : "🔴"} {(Math.abs(hud.bGold - hud.rGold) / 1000).toFixed(1)}k</div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, background: "rgba(8,14,24,0.7)", border: "1px solid rgba(239,68,68,0.5)", borderRadius: 10, padding: "5px 11px", backdropFilter: "blur(4px)" }}>
          <span style={{ color: "#fff", fontWeight: 900, fontSize: 18, fontFamily: "monospace" }}>{hud.rK}</span>
          <span style={{ color: "#fca5a5", fontWeight: 800, fontSize: 13 }}>赤焰軍團</span><span style={{ fontSize: 15 }}>🔥</span>
        </div>
      </div>
      {/* 勝率條 */}
      <div style={{ position: "absolute", top: 52, left: 12, right: 12, height: 6, borderRadius: 99, overflow: "hidden", background: "rgba(0,0,0,0.5)", display: "flex", pointerEvents: "none" }}>
        <div style={{ width: `${hud.winProb * 100}%`, background: "linear-gradient(90deg,#3b82f6,#60a5fa)" }} />
        <div style={{ flex: 1, background: "linear-gradient(90deg,#fca5a5,#ef4444)" }} />
      </div>

      {/* Start / Stop */}
      {!playing && !hud.over && (
        <button onClick={start} style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", zIndex: 10, background: "linear-gradient(135deg,#3b82f6,#1d4ed8)", border: "2px solid #93c5fd", borderRadius: 14, padding: "16px 40px", color: "#fff", fontSize: 20, fontWeight: 900, letterSpacing: "0.08em", cursor: "pointer", boxShadow: "0 8px 40px rgba(59,130,246,0.6)" }}>
          ▶ 開始遊戲 / START
        </button>
      )}
      {playing && (
        <button onClick={stop} style={{ position: "absolute", top: 70, left: 12, zIndex: 10, background: "rgba(239,68,68,0.85)", border: "1px solid #fca5a5", borderRadius: 8, padding: "5px 12px", color: "#fff", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>⏹ 結束</button>
      )}
      <button onClick={() => setAuto((v) => !v)} style={{ position: "absolute", top: 70, right: 12, zIndex: 10, background: auto ? "rgba(96,165,250,0.9)" : "rgba(8,14,24,0.7)", border: `1px solid ${auto ? "#60a5fa" : "rgba(255,255,255,0.3)"}`, borderRadius: 8, padding: "5px 10px", color: "#fff", fontSize: 11, fontWeight: 700, cursor: "pointer" }}>
        {auto ? "⏸ 環繞" : "▶ 環繞"}
      </button>

      {/* 結算 */}
      {hud.over && (
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", zIndex: 12, textAlign: "center", background: "rgba(8,14,24,0.92)", border: `2px solid ${hud.winner === "blue" ? "#3b82f6" : "#ef4444"}`, borderRadius: 16, padding: "26px 44px" }}>
          <div style={{ fontSize: 30 }}>{hud.winner === "blue" ? "🦭" : "🔥"}</div>
          <div style={{ color: hud.winner === "blue" ? "#93c5fd" : "#fca5a5", fontSize: 22, fontWeight: 900, marginTop: 6 }}>{hud.winner === "blue" ? "德國海豹" : "赤焰軍團"} 勝利!</div>
          <button onClick={start} style={{ marginTop: 14, background: "#3b82f6", border: "none", borderRadius: 10, padding: "10px 28px", color: "#fff", fontWeight: 800, fontSize: 14, cursor: "pointer" }}>↻ 再來一場</button>
        </div>
      )}

      <div style={{ position: "absolute", bottom: 10, left: 10, color: "rgba(255,255,255,0.6)", fontSize: 10, background: "rgba(0,0,0,0.45)", padding: "4px 8px", borderRadius: 6, pointerEvents: "none" }}>
        拖曳旋轉 · 滾輪縮放 · 真實邏輯大腦驅動中
      </div>

      {/* 小地圖 */}
      <canvas ref={miniRef} width={150} height={150} style={{ position: "absolute", bottom: 10, right: 10, width: 150, height: 150, borderRadius: 10, border: "1px solid rgba(255,255,255,0.25)", boxShadow: "0 4px 20px rgba(0,0,0,0.5)", pointerEvents: "none" }} />
    </div>
  );
}

// ── Phase 7（方案 A）：暴露既有 battle store，供 MobaBattleAdapter 監聽 over ──
//   僅新增此行 export；store 定義（第 342 行）與所有戰鬥/渲染/snapshot 邏輯零改動。
export { store };
